select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = c.postid and p.id = pl.relatedpostid and p.id = v.postid and u.id = p.owneruserid and u.id = b.userid and u.views<=190 and u.creationdate>=timestamp '2010-07-20 08:05:39' and u.creationdate<=timestamp '2014-08-27 09:31:28';
